    //let vCreateYn = ed_createYn.getValue();
    let vCreateYn = scwin.txt_createYn;

    scwin.f_ContentsDisable();

    $c.gus.cfDisableBtn([b_Cancel, b_Save, b_Cancel2, b_Save2, btFilePopup, btFileImport,
        bAddRow, bUpdateRow, bDeleteRow,
        bAddRow1, bUpdateRow1, bDeleteRow1,
        bAddRow2, bUpdateRow2, bDeleteRow2,
        bAddRow3, bUpdateRow3, bDeleteRow3,
        bAddRow4, bUpdateRow4, bDeleteRow4,
