//-------------------------------------------
// 휴대전화번호 입력 : '숫자', '-'
//-------------------------------------------
scwin.f_checkCharacter = function (e) {
    let key = e.keyCode;

    // 숫자(48~57), 하이픈(45) 외 입력 차단
    if (key !== 45 && (key < 48 || key > 57)) {
        $c.win.alert("휴대전화번호는 '숫자', '-' 만 입력 가능합니다.");
        e.preventDefault();   // WebSquare 방식 차단
    }
}

