//-------------------------------------------------------------------------
// 지급조건 지급계좌 순번할당..
//-------------------------------------------------------------------------
scwin.f_SetSEQ = function () {
    let vTabIndex = scwin.txt_payIdx;
    let vTmpSeq = 0;
    let vTmpVal;
    let vObjGrd;
    let vPayCountRow = 0;
    let dl;

    if (vTabIndex == 1) {
        vPayCountRow = ds_collMoneyCond.getRowCount();
        dl = $c.gus.object(ds_collMoneyCond);
    } else if (vTabIndex == 2) {
        vPayCountRow = ds_payCond.getRowCount();
        dl = $c.gus.object(ds_payCond);
    } else if (vTabIndex == 3) {
        vPayCountRow = ds_payAcnt.getRowCount();
        dl = $c.gus.object(ds_payAcnt);
    }

    if (vPayCountRow > 0) {
        for (i = 0; i < vPayCountRow; i++) {
            vTmpVal = dl.getCellData(i, "seq");
            if (vTmpVal > vTmpSeq) {
                vTmpSeq = vTmpVal;
            }
        }
    }

    return Number(vTmpSeq) + 1;
}

