    //ds_customerFileDetail.Reset();
    sbm_customerFileDetail.action = "/cm.bc.clnt.clntmgnt.RetrieveCustomerFileListCMD.do?clntNo=" + vClntNo + "&regFileDtFrom=" + vRegFileDtFrom + "&regFileDtTo=" + vRegFileDtTo + "&fileTypeCd=" + vFileTypeCd;
