/*
<!-- Gauce Tab선택시 행추가, 행수정, 행삭제 버튼 활성화 비활성화  -->
 language=JavaScript for=mxTab event=OnSelChanged(index)>
*/
scwin.tac_tab_onchange = function (tabId, index, userTabId) {
    if (index == 0) {
        if (scwin.g_sLoginDept == "00009") {//채권팀
            btn_table0.show();
        } else {
            btn_table0.hide();
        }

        scwin.txt_payIdx = "1";
        if (scwin.txt_saveType == "0" || scwin.txt_saveType == "1") {  // 0:신규, 1:수정, 2:조회, 3:저장
            $c.gus.cfEnableBtnOnly([bAddRow, bUpdateRow, bDeleteRow]);
        }

        tac_tab.hideTab(6);
    } else if (index == 1) {
        btn_table0.show();
        scwin.txt_payIdx = "2";
        if (scwin.txt_saveType == "0" || scwin.txt_saveType == "1") {  // 0:신규, 1:수정, 2:조회, 3:저장
            $c.gus.cfEnableBtnOnly([bAddRow1, bUpdateRow1, bDeleteRow1]);
        }
        tac_tab.hideTab(6);
    } else if (index == 2) {
        btn_table0.show();
        scwin.txt_payIdx = "3";
        if (scwin.txt_saveType == "0" || scwin.txt_saveType == "1") {
            $c.gus.cfEnableBtnOnly([bAddRow2, bUpdateRow2, bDeleteRow2]);
        }
        tac_tab.hideTab(6);
    } else if (index == 3) {
        btn_table0.show();
        scwin.txt_payIdx = "4";
        if (scwin.txt_saveType == "0" || scwin.txt_saveType == "1") {
            $c.gus.cfEnableBtnOnly([bAddRow3, bUpdateRow3, bDeleteRow3]);
        }
        tac_tab.hideTab(6);
    } else if (index == 4) { //매입거래처
        btn_table0.show();
        scwin.txt_payIdx = "5";
        if (scwin.txt_saveType == "0" || scwin.txt_saveType == "1") {
            $c.gus.cfEnableBtnOnly([bAddRow4, bUpdateRow4, bDeleteRow4]);
        }
        //mxTab_page7.style.display = 'none';
        tac_tab.hideTab(6);
    } else if (index == 5) { // 가상계좌
        gr_tb_Grid6_btn.hide();
    } else if (index == 6) {
        btn_table0.show();
        $c.gus.cfEnableObj(lc_fileTypeCd, true);	 // 자료구분
        scwin.txt_payIdx = "7";
        if (scwin.txt_saveType == "0" || scwin.txt_saveType == "1") {
            $c.gus.cfEnableBtnOnly([bAddRow5, bUpdateRow5, bDeleteRow5, btCustomerFilePopup]);
        } else {
            $c.gus.cfDisableBtn([btCustomerFilePopup]);
        }
        //mxTab_page7.style.display = 'block';
        tac_tab.showTab(6);
    }

    if (index == 3) {
        btn_table0.hide();// ToBe랑 AsIs 버튼 영역이 다르다.
    } else {
        btn_table0.show();//
    }
};

