scwin.fn_undo = function (paramObj) {
    for (var idx = paramObj.getRowCount() - 1; idx > -1; idx--) {
        var rStat = paramObj.getRowStatus(idx);
        if (rStat == 'C') {
            //신규면 삭제
            paramObj.removeRow(idx);
        } else if (rStat == 'U') {
            paramObj.undoRow(idx);
        }
    }
};


scwin.f_downExcelSheet = async function () {

    var vDsIdx = scwin.txt_payIdx;
    var vObjGrd;
    var sheetTitle;


    if (vDsIdx == "1") {
        if (ds_collMoneyCond.getRowCount() < 1) {
            $c.win.alert("수금조건내역이 없습니다.");
            return false;
        }
        vObjGrd = "gr_tb_Grid1";
        sheetTitle = "수금조건";
    } else if (vDsIdx == "2") {
        if (ds_payCond.getRowCount() < 1) {
            $c.win.alert("지급조건내역이 없습니다.");
            return false;
        }
        vObjGrd = "gr_tb_Grid2";
        sheetTitle = "지급조건";
    } else if (vDsIdx == "3") {
        if (ds_payAcnt.getRowCount() < 1) {
            $c.win.alert("지급계좌내역이 없습니다.");
            return false;
        }
        vObjGrd = "gr_tb_Grid3";
        sheetTitle = "지급계좌";
    } else if (vDsIdx == "5") {
        if (ds_contractFileDetail.getRowCount() < 1) {
            $c.win.alert("계약서 파일이 없습니다.");
            return false;
        }
        vObjGrd = "gr_tb_Grid5";
        sheetTitle = "계약서 파일";
    } else if (vDsIdx == "7") {
        if (ds_contractFileDetail.getRowCount() < 1) {
            $c.win.alert("거래처자료가 없습니다.");
            return false;
        }
        vObjGrd = "gr_tb_Grid7";
        sheetTitle = "거래처자료";
    }

    var objGrd = eval(vObjGrd);

    ret = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (ret) {
        //cfGridToExcel(objGrd, sheetTitle, sheetTitle, 2+4+8+16);	
        let gridId = objGrd;
        let infoArr = [];
        let options = {
            fileName: sheetTitle + ".xlsx",    // + ".xls",
            sheetName: sheetTitle,
        };
        $c.data.downloadGridViewExcel(gridId, options, infoArr);
    }
}


scwin.covTelNumberValidator_validate = function (value) {
    var format = /^0[0-9]{1,2}-\d{1,4}-\d\d\d\d/g //국내전화
    var nCnt = 0;
    for (var i = 0; i < value.length; i++) {
        var c = value.charAt(i);
        if (c == "-") nCnt++;
    }

    if (nCnt == 3) format = /^[1-9]{1,2}-\d{1,4}-\d{1,4}-\d\d\d\d/g // 국제전화

    if (value.search(format) == -1) {
        $c.win.alert($c.data.getMessage(MSG_CM_ERR_038, [" 전화 번호 "]));
        return false;
    }
    return true;
}


